class GpzEngine { static String strategy({required double magneticGroundRisk,required double quartzScore,required double ironScore}){ if(magneticGroundRisk>0.75){return 'GPZ 7000: Ground Type = Severe/Difficult | Gold Mode = High Yield | Sensitivity = 8–11 | Audio Smoothing = Low/On | Swing = بطيء جدًا.';} if(magneticGroundRisk<0.45 && quartzScore>0.70){return 'GPZ 7000: Ground Type = Normal | Gold Mode = General/Deep | Sensitivity = 12–16 | Audio Smoothing = Off.';} return 'GPZ 7000: ضبط متوسط | Gold Mode = General | Ground Type = Difficult عند أكاسيد عالية | Sensitivity = 10–13.'; }}
